import{_ as e,o as a,c as l,a2 as o}from"./chunks/framework.BQ1gajhD.js";const q=JSON.parse('{"title":"苏州街（买卖街）","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/summer-palace/suzhou-street.md","filePath":"landmarks/summer-palace/suzhou-street.md","lastUpdated":1784720050000}'),r={name:"landmarks/summer-palace/suzhou-street.md"};function n(s,t,i,d,u,h){return a(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="苏州街-买卖街" tabindex="-1">苏州街（买卖街） <a class="header-anchor" href="#苏州街-买卖街" aria-label="Permalink to &quot;苏州街（买卖街）&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1566455123644-5c94561acf9b?w=1200&amp;q=80" alt="苏州街"></p><blockquote><p>&quot;一条买卖街，半部帝王心。&quot; —— 紫禁城外的人间烟火，皇家深宫里的&quot;过家家&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>苏州街位于颐和园后湖（后溪河）两岸，又称&quot;买卖街&quot;，是乾隆年间仿江南水乡市肆而建的一条皇家商业水街。它全长约300米，两岸鳞次栉比地排列着60余家店铺：茶楼、酒肆、药铺、绸缎庄、钱庄、帽店、糕点铺、古玩店……青瓦白墙、招幌高悬，小桥流水穿街而过，恍如把姑苏阊门外的十里繁华整体搬进了皇家禁苑。</p><p>这条街的诞生源于乾隆的江南情结。乾隆六下江南，对苏州水乡的市井风情念念不忘，回京后便命人在后湖两岸仿建水街，让无法出宫的帝后们也能&quot;足不出园逛苏州&quot;。</p><p>咸丰十年（1860年）苏州街随清漪园一同毁于英法联军大火，此后荒废百余年。1986年按原样重建，1990年正式对外开放，是颐和园中最年轻的&quot;古迹&quot;。</p><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年代</th><th style="text-align:left;">大事</th></tr></thead><tbody><tr><td style="text-align:left;">清乾隆年间</td><td style="text-align:left;">仿苏州水街始建&quot;买卖街&quot;，帝后&quot;逛街&quot;之所</td></tr><tr><td style="text-align:left;">咸丰十年（1860）</td><td style="text-align:left;">随清漪园毁于英法联军大火，此后荒废百余年</td></tr><tr><td style="text-align:left;">1986年</td><td style="text-align:left;">依据清宫图档按原址原制重建</td></tr><tr><td style="text-align:left;">1990年</td><td style="text-align:left;">正式对外开放，店员由真人经营</td></tr></tbody></table><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>全长</strong></td><td style="text-align:left;">约300米，沿后溪河两岸展开</td></tr><tr><td style="text-align:left;"><strong>店铺</strong></td><td style="text-align:left;">60余家</td></tr><tr><td style="text-align:left;"><strong>格局</strong></td><td style="text-align:left;">前店后河，跨河拱桥相连，码头临水，招幌高悬</td></tr><tr><td style="text-align:left;"><strong>风格</strong></td><td style="text-align:left;">江南水街风貌，青瓦白墙，尺度刻意缩小以求亲切</td></tr><tr><td style="text-align:left;"><strong>游览方式</strong></td><td style="text-align:left;">沿河岸步行或乘摇橹船穿行水街</td></tr></tbody></table><p>苏州街的妙处在于&quot;小&quot;与&quot;真&quot;：店铺门脸刻意做得比实物略小，沿河一字排开，临水设码头，跨河架拱桥，岸上行人摩肩，水中画舫往来，江南水街的格局一应俱全。</p><p>店铺虽为复建，招幌、匾额皆按清宫档案复原，行走其间，耳边是叫卖声与丝竹声，恍惚回到二百年前的姑苏城外。主要店铺类型包括：</p><table tabindex="0"><thead><tr><th style="text-align:left;">业态</th><th style="text-align:left;">代表店铺</th></tr></thead><tbody><tr><td style="text-align:left;">茶楼酒肆</td><td style="text-align:left;">各式茶馆、酒楼，可临水品茗</td></tr><tr><td style="text-align:left;">绸缎百货</td><td style="text-align:left;">云锦斋等绸缎庄</td></tr><tr><td style="text-align:left;">钱庄当铺</td><td style="text-align:left;">品泉斋等钱庄</td></tr><tr><td style="text-align:left;">糕点小吃</td><td style="text-align:left;">漱芳斋等点心铺</td></tr><tr><td style="text-align:left;">医药文玩</td><td style="text-align:left;">药铺、古玩铺、字画铺</td></tr></tbody></table><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="太监宫女扮-店员" tabindex="-1">太监宫女扮&quot;店员&quot; <a class="header-anchor" href="#太监宫女扮-店员" aria-label="Permalink to &quot;太监宫女扮&quot;店员&quot;&quot;">​</a></h3><p>苏州街建成时，乾隆定下规矩：街上的&quot;掌柜&quot;&quot;伙计&quot;&quot;茶博士&quot;全部由太监宫女扮演，商品则是内务府预备的奇珍杂货。每年皇帝携后妃驾临&quot;逛街&quot;，太监们便扯开嗓子吆喝，宫女们扮作买办讨价还价，一时市声鼎沸。</p><p>据说乾隆最爱在绸缎庄&quot;购物&quot;，由太监扮的掌柜故意抬价，再由宫女扮的&quot;顾客&quot;砍价，最终以&quot;御笔钦定&quot;成交，君臣尽欢。深宫高墙之内，这是一场心照不宣的&quot;人间烟火&quot;cosplay——帝王要的不是买卖，而是那份寻常百姓才有的逛街之乐。</p><h3 id="灰烬中的重生" tabindex="-1">灰烬中的重生 <a class="header-anchor" href="#灰烬中的重生" aria-label="Permalink to &quot;灰烬中的重生&quot;">​</a></h3><p>1860年英法联军的大火烧了三天三夜，后湖两岸的买卖街化为焦土，此后一百二十年里只余断壁残垣与河床荒草。1986年，园林部门依据清宫《颐和园图》和档案记载，按原址、原制、原貌重建苏州街，连店铺的字号招幌都逐一考证复原。</p><p>1990年开放当日，许多老北京赶来&quot;认亲&quot;——他们小时候听祖辈讲过的买卖街，终于从故事里走了回来。如今街上的店员换成了真营业员，卖着茶叶、糕点和文创，那份市井气，竟真的续上了。</p><h3 id="后溪河的水系密码" tabindex="-1">后溪河的水系密码 <a class="header-anchor" href="#后溪河的水系密码" aria-label="Permalink to &quot;后溪河的水系密码&quot;">​</a></h3><p>苏州街不是凭空造景，它依托的后溪河（后湖）是一条精心设计的人工水道：引昆明湖水东流，绕万寿山北麓蜿蜒而过，既解决了后山的排水，又造出了&quot;水随山转、街因水成&quot;的江南意境。重建时考古清理出乾隆朝的河底石基与驳岸遗址，成为复原的坐标依据——可以说，今天的苏州街是踩着两百多年前的地基重新站起来的。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><strong>水街格局</strong>：两岸店铺夹河而立，小桥流水穿行其间，是北方园林中罕见的江南水街实景。</li><li><strong>招幌匾额</strong>：留意各家店铺的老式招幌与匾额，云锦斋、品泉斋、漱芳斋……一块匾就是一门营生。</li><li><strong>摇橹船穿街</strong>：乘摇橹船从后湖穿过苏州街，船娘摇桨、两岸吆喝，最接近当年帝后游街的体验（需另购票）。</li><li><strong>临水戏台</strong>：街中小戏台偶有民俗表演，评弹、京韵大鼓轮番上阵，逛累了正好歇脚听曲。</li><li><strong>北宫门起点</strong>：苏州街紧邻北宫门，从后门进园的游客第一眼便是它，&quot;未见湖山，先闻市声&quot;的开场别有设计。</li></ol><h2 id="拍照机位" tabindex="-1">拍照机位 <a class="header-anchor" href="#拍照机位" aria-label="Permalink to &quot;拍照机位&quot;">​</a></h2><ol><li><strong>跨河拱桥上</strong>：站在小拱桥上顺河拍，两岸店铺招幌层层叠叠，最出&quot;姑苏繁华图&quot;的感觉。</li><li><strong>临水码头</strong>：低机位拍河面倒影与画舫，雨后或清晨水面平静时效果最佳。</li><li><strong>招幌特写</strong>：各色布招幌随风招展，长焦压缩后颇有古意。</li></ol><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ol><li>苏州街为园中园，需持联票或另购10元门票；街内购物消费另计，价格与普通景区相仿。</li><li>建议上午早些抵达，店铺开门、游人尚少，拍照最有&quot;包场&quot;感。</li><li>街全长仅300米，步行15分钟即走完，若乘摇橹船放慢节奏体验更佳。</li><li>从北宫门入园后先逛苏州街，再上山经四大部洲至<a href="/beijing-travel-guide/landmarks/summer-palace/foxiang-ge.html">佛香阁</a>，是<a href="/beijing-travel-guide/landmarks/summer-palace/">北宫门线</a>的标准开场。</li><li>后湖一带还有<a href="/beijing-travel-guide/landmarks/summer-palace/xiequ-yuan.html">谐趣园</a>（东端）和须弥灵境遗址（中段），可与苏州街串联成&quot;后山半日游&quot;，人少清净，与前山的喧闹恍如两园。</li><li>街内小吃可以尝鲜，但正餐建议留到园外的海淀老字号，性价比更高。</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q：苏州街需要单独购票吗？</strong></p><p>苏州街属园中园，单独购票10元；持颐和园联票可直接进入。</p><p><strong>Q：苏州街里的东西是真的在卖吗？</strong></p><p>是真的开门营业：茶叶、糕点、文创、丝绸都可实买，也有临水茶馆可坐——当然，价格按景区标准。</p><p><strong>Q：苏州街是乾隆时期的原物吗？</strong></p><p>不是。原街1860年被英法联军焚毁，荒废百余年后于1986年按清宫图档原址重建，1990年开放，是颐和园最年轻的&quot;古迹&quot;。</p><p><strong>Q：苏州街适合带孩子吗？</strong></p><p>很适合。小吃、叫卖、摇橹船、民俗表演，孩子全程有得看有得玩，比殿宇陈列更有吸引力。</p><hr><p><strong>📍 位置</strong>：颐和园后湖（后溪河）两岸，北宫门南侧 <strong>⏱️ 建议游览</strong>：30-40分钟 <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/summer-palace/">颐和园概览</a></p>',40)])])}const p=e(r,[["render",n]]);export{q as __pageData,p as default};
